  1	import * as React from 'react';
  2	import { Card, CardBody, CardHeader, Title, TitleSizes, Tooltip, TooltipPosition } from '@patternfly/react-core';
  3	import { ServiceDetailsInfo, WorkloadOverview } from '../../types/ServiceInfo';
  4	import { AppWorkload } from '../../types/App';
  5	import { isMultiCluster } from '../../config';
  6	import { Labels } from '../../components/Label/Labels';
  7	import { kialiStyle } from 'styles/StyleUtils';
  8	import { LocalTime } from '../../components/Time/LocalTime';
  9	import { renderAPILogo } from '../../components/Logo/Logos';
 10	import { TextOrLink } from '../../components/Link/TextOrLink';
 11	import { KialiIcon } from '../../config/KialiIcon';
 12	import { HealthIndicator } from '../../components/Health/HealthIndicator';
 13	import { PFBadge, PFBadges } from '../../components/Pf/PfBadges';
 14	import { DetailDescription } from '../../components/DetailDescription/DetailDescription';
 15	import { AmbientLabel, tooltipMsgType } from '../../components/Ambient/AmbientLabel';
 16	import { infoStyle } from 'styles/IconStyle';
 17	import { classes } from 'typestyle';
 18	import { getIstioObjectGVK } from '../../utils/IstioConfigUtils';
 19	import { getAppLabelName } from 'config/ServerConfig';
 20	
 21	interface ServiceInfoDescriptionProps {
 22	  namespace: string;
 23	  serviceDetails?: ServiceDetailsInfo;
 24	}
 25	
 26	const resourceListStyle = kialiStyle({
 27	  marginBottom: '0.75rem',
 28	  $nest: {
 29	    '& > ul > li span': {
 30	      float: 'left',
 31	      width: '125px',
 32	      fontWeight: 700
 33	    }
 34	  }
 35	});
 36	
 37	const iconStyle = kialiStyle({
 38	  display: 'inline-block'
 39	});
 40	
 41	const serviceInfoStyle = kialiStyle({
 42	  verticalAlign: '-0.125rem'
 43	});
 44	
 45	const healthIconStyle = kialiStyle({
 46	  marginLeft: '0.5rem',
 47	  verticalAlign: '-0.075rem'
 48	});
 49	
 50	const additionalItemStyle = kialiStyle({
 51	  display: 'flex',
 52	  alignItems: 'center'
 53	});
 54	
 55	export const ServiceDescription: React.FC<ServiceInfoDescriptionProps> = (props: ServiceInfoDescriptionProps) => {
 56	  const apps: string[] = [];
 57	  const workloads: AppWorkload[] = [];
 58	
 59	  if (props.serviceDetails) {
 60	    if (props.serviceDetails.workloads) {
 61	      props.serviceDetails.workloads
 62	        .sort((w1: WorkloadOverview, w2: WorkloadOverview) => (w1.name < w2.name ? -1 : 1))
 63	        .forEach(wk => {
 64	          // ignore app links for ambient infra
 65	          if (wk.labels && !wk.isWaypoint && !wk.isZtunnel) {
 66	            const appLabelName = getAppLabelName(wk.labels);
 67	            if (appLabelName) {
 68	              const appName = wk.labels[appLabelName];
 69	              if (!apps.includes(appName)) {
 70	                apps.push(appName);
 71	              }
 72	            }
 73	          }
 74	
 75	          workloads.push({
 76	            namespace: wk.namespace,
 77	            workloadName: wk.name,
 78	            gvk: getIstioObjectGVK(wk.resourceVersion, wk.type),
 79	            istioSidecar: wk.istioSidecar,
 80	            isAmbient: wk.isAmbient,
 81	            isGateway: wk.isGateway,
 82	            isWaypoint: wk.isWaypoint,
 83	            isZtunnel: wk.isZtunnel,
 84	            serviceAccountNames: wk.serviceAccountNames,
 85	            labels: wk.labels ?? {}
 86	          });
 87	        });
 88	    }
 89	  }
 90	
 91	  // We will show service labels only when there is some label that is not present in the selector
 92	  let showServiceLabels = false;
 93	
 94	  if (props.serviceDetails && props.serviceDetails.service.labels && props.serviceDetails.service.selectors) {
 95	    const keys = Object.keys(props.serviceDetails.service.labels);
 96	
 97	    for (let i = 0; i < keys.length; i++) {
 98	      const key = keys[i];
 99	      const value = props.serviceDetails.service.labels[key];
100	
101	      if (props.serviceDetails.service.selectors[key] !== value) {
102	        showServiceLabels = true;
103	        break;
104	      }
105	    }
106	  }
107	
108	  const serviceProperties = (
109	    <div key="properties-list" className={resourceListStyle}>
110	      <ul style={{ listStyleType: 'none' }}>
111	        {props.serviceDetails && (
112	          <li>
113	            <span>Created</span>
114	
115	            <div style={{ display: 'inline-block' }}>
116	              <LocalTime time={props.serviceDetails.service.createdAt} />
117	            </div>
118	          </li>
119	        )}
120	
121	        {props.serviceDetails && (
122	          <li>
123	            <span>Version</span>
124	            {props.serviceDetails.service.resourceVersion}
125	          </li>
126	        )}
127	
128	        {props.serviceDetails?.service?.additionalDetails?.map((additionalItem, idx) => {
129	          return (
130	            <li key={`additional-details-${idx}`} id={`additional-details-${idx}`}>
131	              <div className={additionalItemStyle}>
132	                <span>{additionalItem.title}</span>
133	                {additionalItem.icon && renderAPILogo(additionalItem.icon, undefined, idx)}
134	              </div>
135	              <TextOrLink text={additionalItem.value} urlTruncate={64} />
136	            </li>
137	          );
138	        })}
139	      </ul>
140	    </div>
141	  );
142	
143	  const serviceName = props.serviceDetails ? props.serviceDetails.service.name : 'Service';
144	  let serviceBadge = PFBadges.Service;
145	
146	  if (props.serviceDetails && props.serviceDetails.service) {
147	    switch (props.serviceDetails.service.type) {
148	      case 'External':
149	        serviceBadge = PFBadges.ExternalService;
150	        break;
151	      case 'Federation':
152	        serviceBadge = PFBadges.FederatedService;
153	        break;
154	      default:
155	        serviceBadge = PFBadges.Service;
156	    }
157	  }
158	
159	  return (
160	    <Card id="ServiceDescriptionCard">
161	      <CardHeader>
162	        <Title headingLevel="h5" size={TitleSizes.lg}>
163	          <div key="service-icon" className={iconStyle}>
164	            <PFBadge badge={serviceBadge} position={TooltipPosition.top} />
165	          </div>
166	
167	          {serviceName}
168	
169	          <Tooltip
170	            position={TooltipPosition.right}
171	            content={<div style={{ textAlign: 'left' }}>{serviceProperties}</div>}
172	          >
173	            <KialiIcon.Info className={classes(infoStyle, serviceInfoStyle)} />
174	          </Tooltip>
175	
176	          <span className={healthIconStyle}>
177	            <HealthIndicator id={serviceName} health={props.serviceDetails ? props.serviceDetails.health : undefined} />
178	          </span>
179	
180	          {props.serviceDetails?.isAmbient && <AmbientLabel tooltip={tooltipMsgType.service} />}
181	        </Title>
182	
183	        {props.serviceDetails?.service.cluster && isMultiCluster && (
184	          <div key="cluster-icon" className={iconStyle}>
185	            <PFBadge badge={PFBadges.Cluster} position={TooltipPosition.right} /> {props.serviceDetails.service.cluster}
186	          </div>
187	        )}
188	      </CardHeader>
189	
190	      <CardBody>
191	        {props.serviceDetails && showServiceLabels && (
192	          <Labels labels={props.serviceDetails.service.labels} tooltipMessage="Labels defined on the Service" />
193	        )}
194	
195	        {props.serviceDetails && (
196	          <Labels
197	            labels={props.serviceDetails.service.selectors}
198	            tooltipMessage={`Labels defined on the ${showServiceLabels ? 'Selector' : 'Service and Selector'}`}
199	          />
200	        )}
201	
202	        <DetailDescription
203	          namespace={props.namespace}
204	          apps={apps.length > 0 ? apps : undefined}
205	          workloads={workloads}
206	          health={props.serviceDetails?.health}
207	          cluster={props.serviceDetails?.service.cluster}
208	          waypointWorkloads={props.serviceDetails?.waypointWorkloads}
209	        />
210	      </CardBody>
211	    </Card>
212	  );
213	};

